                    animation: 'fadeIn 0.3s ease-out'
                }}>
                    <div style={{ background: 'var(--bg-secondary)', color: 'var(--text-primary)', padding: '32px', borderRadius: '24px', minWidth: '400px', maxWidth: '90%', boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.25)', border: '1px solid rgba(255,255,255,0.1)', animation: 'slideUp 0.4s cubic-bezier(0.16, 1, 0.3, 1)' }}>
                        
                        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', borderBottom: '1px solid var(--bg-tertiary)', paddingBottom: '16px' }}>
                            <h3 style={{ margin: 0, fontSize: '1.5rem', fontWeight: '800', display: 'flex', alignItems: 'center', gap: '10px' }}>
                                <div style={{ background: 'var(--accent-primary)', color: 'white', width: '36px', height: '36px', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1rem', boxShadow: '0 4px 10px rgba(37, 99, 235, 0.3)' }}>
                                    <i className="fa-solid fa-ticket-simple"></i>
                                </div>
                                Book Slot <span style={{ color: 'var(--accent-primary)', marginLeft: '4px' }}>{slots.find(s => s._id === selectedSlotId)?.slotNumber}</span>
                            </h3>
                            <button onClick={() => setShowModal(false)} style={{ background: 'none', border: 'none', fontSize: '1.2rem', color: 'var(--text-muted)', cursor: 'pointer', transition: 'var(--transition)' }} onMouseOver={e => e.target.style.color = 'var(--status-danger)'} onMouseOut={e => e.target.style.color = 'var(--text-muted)'}>
                                <i className="fa-solid fa-xmark"></i>
                            </button>
                        </div>

                        <div className="input-group">
                            <label><i className="fa-regular fa-id-card"></i> Vehicle Number</label>
                            <input type="text"
                                value={bookingData.vehicleNumber}
                                onChange={e => {
                                    setBookingData({ ...bookingData, vehicleNumber: e.target.value.toUpperCase() });
                                    setValidationError("");
                                }}
                                placeholder="e.g. MH 12 AB 1234"
                                style={{ borderColor: validationError ? 'var(--status-danger)' : 'transparent', textTransform: 'uppercase' }}
                            />
                            {validationError && <p style={{ color: 'var(--status-danger)', fontSize: '0.85rem', marginTop: '6px', fontWeight: '500' }}><i className="fa-solid fa-triangle-exclamation"></i> {validationError}</p>}
                        </div>

                        <div className="input-group">
                            <label><i className="fa-solid fa-car-side"></i> Vehicle Type</label>
                            <div style={{ position: 'relative' }}>
                                <select
                                    value={bookingData.vehicleType}
                                    onChange={e => setBookingData({ ...bookingData, vehicleType: e.target.value })}
                                    style={{ appearance: 'none', cursor: 'pointer' }}
                                >
                                    <option value="Four-wheeler">Four-wheeler 🚗</option>
                                    <option value="Two-wheeler">Two-wheeler 🏍️</option>
                                </select>
                                <i className="fa-solid fa-chevron-down" style={{ position: 'absolute', right: '16px', top: '50%', transform: 'translateY(-50%)', color: 'var(--text-muted)', pointerEvents: 'none' }}></i>
                            </div>
                        </div>

                        <div style={{ background: 'var(--bg-tertiary)', padding: '16px', borderRadius: '12px', marginBottom: '24px' }}>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '16px' }}>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: '700', color: 'var(--text-secondary)', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>Start Time</label>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                                        <input type="date"
                                            value={bookingData.startDate}
                                            onChange={e => setBookingData({ ...bookingData, startDate: e.target.value })}
                                            style={{ padding: '10px 12px', background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)' }}
                                        />
                                        <input type="time"
                                            value={bookingData.startTime}
                                            onChange={e => setBookingData({ ...bookingData, startTime: e.target.value })}
                                            style={{ padding: '10px 12px', background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)' }}
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label style={{ display: 'block', fontSize: '0.85rem', fontWeight: '700', color: 'var(--text-secondary)', marginBottom: '8px', textTransform: 'uppercase', letterSpacing: '0.5px' }}>End Time</label>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
                                        <input type="date"
                                            value={bookingData.endDate}
                                            onChange={e => setBookingData({ ...bookingData, endDate: e.target.value })}
                                            style={{ padding: '10px 12px', background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)' }}
                                        />
                                        <input type="time"
                                            value={bookingData.endTime}
                                            onChange={e => setBookingData({ ...bookingData, endTime: e.target.value })}
                                            style={{ padding: '10px 12px', background: 'var(--bg-secondary)', border: '1px solid var(--border-subtle)' }}
                                        />
                                    </div>
                                </div>
                            </div>
                        </div>

                        <button className="btn-primary" onClick={handleConfirmBooking} style={{ width: '100%', padding: '16px', fontSize: '1.1rem' }}>
                            Confirm & Pay <i className="fa-solid fa-arrow-right"></i>
                        </button>
                    </div>
                </div>
            )}

            {/* RENDER DYNAMIC LAYOUT */}
            <div className="parking-layout" style={{ marginTop: '20px' }}>
                {getLayout()}
            </div>
        </div>
    );
}
